#include <stdio.h>
#include <string.h>

int max(int a, int b) { return a > b ? a : b; }

int longestNonDecreasingSubsequence(char *s) {
    int n = strlen(s);
    int maxLen = 0;
    for (int i = 0; i < n; i++) {
        int len = 0;
        char prev = '0';
        for (int j = i; j < n; j++) {
            if (s[j] >= prev) {
                len++;
                prev = s[j];
            }
        }
        maxLen = max(maxLen, len);
    }
    return maxLen;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        char s[100001];
        scanf("%s", s);
        int n = strlen(s);
        int maxLen = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i; j < n; j++) {
                char substr[j - i + 1 + 1];
                strncpy(substr, s + i, j - i + 1);
                substr[j - i + 1] = '\0';
                char remaining[n - (j - i + 1) + 1];
                strncpy(remaining, s, i);
                remaining[i] = '\0';
                strcat(remaining, s + j + 1);
                for (int k = 0; k <= n - (j - i + 1); k++) {
                    char result[n + 1];
                    strncpy(result, remaining, k);
                    result[k] = '\0';
                    strcat(result, substr);
                    strcat(result, remaining + k);
                    maxLen = max(maxLen, longestNonDecreasingSubsequence(result));
                }
            }
        }
        printf("%d\n", maxLen);
    }
    return 0;
}

