int main() {
    int t;
    cin >> t;
    while (t--) {
        string s;
        cin >> s;
        int n = s.length();
        int maxLen = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i; j < n; j++) {
                string substr = s.substr(i, j - i + 1);
                string remaining = s.substr(0, i) + s.substr(j + 1);
                for (int k = 0; k <= n - (j - i + 1); k++) {
                    string result = remaining.substr(0, k) + substr + remaining.substr(k);
                    maxLen = max(maxLen, longestNonDecreasingSubsequence(result));
                }
            }
        }
        cout << maxLen << endl;
    }
    return 0;
}

