import java.util.Scanner;
public class Main {
    public static int longestNonDecreasingSubsequence(String s) {
        int n = s.length();
        int maxLen = 0;
        for (int i = 0; i < n; i++) {
            int len = 0;
            char prev = '0';
            for (int j = i; j < n; j++) {
                if (s.charAt(j) >= prev) {
                    len++;
                    prev = s.charAt(j);
                }
            }
            maxLen = Math.max(maxLen, len);
        }
        return maxLen;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            String s = sc.next();
            int n = s.length();
            int maxLen = 0;
            for (int i = 0; i < n; i++) {
                for (int j = i; j < n; j++) {
                    String substr = s.substring(i, j + 1);
                    String remaining = s.substring(0, i) + s.substring(j + 1);
                    for (int k = 0; k <= n - (j - i + 1); k++) {
                        String result = remaining.substring(0, k) + substr + remaining.substring(k);
                        maxLen = Math.max(maxLen, longestNonDecreasingSubsequence(result));
                    }
                }
            }
            System.out.println(maxLen);
        }
    }
}

